.darma-loader-darma-custom-081 {
  width: 40px;
  aspect-ratio: 1;
  border-radius: 50%;
  background: var(--loader-color, #f03355);
  clip-path: polygon(0 0,100% 0,100% 100%,0 100%);
  animation: darma-loader-darma-custom-081-l1 2s infinite cubic-bezier(0.3,1,0,1);
}
@keyframes darma-loader-darma-custom-081-l1 {
  33% {border-radius: 0;background: var(--loader-secondary-color, #514b82) ;clip-path: polygon(0 0,100% 0,100% 100%,0 100%)}
  66% {border-radius: 0;background: #ffa516 ;clip-path: polygon(50% 0,50% 0,100% 100%,0 100%)}
}

